{
  "system": "AJCC Cancer Staging System, 9th Edition (2022)",
  "t_stages": [
    {
      "stage": "TX",
      "description": "Primary tumor not assessed"
    },
    {
      "stage": "T0",
      "description": "No evidence of primary tumor"
    },
    {
      "stage": "T1",
      "description": "Tumor less than or equal to 2 cm in greatest dimension"
    },
    {
      "stage": "T2",
      "description": "Tumor greater than 2 cm but less than or equal to 5 cm in greatest dimension"
    },
    {
      "stage": "T3",
      "description": "Tumor greater than 5 cm in greatest dimension"
    },
    {
      "stage": "T4",
      "description": "Tumor of any size invades adjacent organ(s), such as the vagina, urethra, or bladder"
    }
  ],
  "n_stages": [
    {
      "stage": "NX",
      "description": "Regional lymph nodes cannot be assessed"
    },
    {
      "stage": "N0",
      "description": "No tumor involvement of regional lymph node(s)"
    },
    {
      "stage": "N1",
      "description": "Tumor involvement of regional lymph node(s)"
    },
    {
      "stage": "N1a",
      "description": "Tumor involvement of inguinal, mesorectal, superior rectal, internal iliac, or obturator lymph node(s)"
    },
    {
      "stage": "N1b",
      "description": "Tumor involvement of external iliac lymph node(s)"
    },
    {
      "stage": "N1c",
      "description": "Tumor involvement of N1b (external iliac) with any N1a node(s)"
    }
  ],
  "m_stages": [
    {
      "stage": "cM0",
      "description": "No distant metastasis"
    },
    {
      "stage": "cM1",
      "description": "Distant metastasis"
    },
    {
      "stage": "pM1",
      "description": "Microscopic confirmation of distant metastasis"
    }
  ],
  "stage_groups": [
    {
      "group": "Stage I",
      "criteria": "T1, N0, M0",
      "clinical_meaning": "Small tumor (≤2 cm) limited to the anal canal without lymph node involvement or distant metastasis",
      "five_yr_survival": "Localized disease: 80% five-year survival (SEER data 1999-2006)",
      "treatment_intent": "Curative; for anal canal: chemoRT; for perianal: local excision if well/moderately differentiated T1N0 or select T2N0 not involving sphincter"
    },
    {
      "group": "Stage IIA",
      "criteria": "T2, N0, M0",
      "clinical_meaning": "Tumor >2 cm but ≤5 cm without lymph node involvement or distant metastasis",
      "five_yr_survival": "Localized disease: 80% five-year survival",
      "treatment_intent": "Curative; chemoRT for anal canal; for perianal: local excision if select T2N0 not involving sphincter, otherwise chemoRT"
    },
    {
      "group": "Stage IIB",
      "criteria": "T1–T2, N1, M0",
      "clinical_meaning": "Small to moderate tumor with regional lymph node involvement but no distant metastasis",
      "five_yr_survival": "Regional disease: 60% five-year survival",
      "treatment_intent": "Curative; chemoRT"
    },
    {
      "group": "Stage IIIA",
      "criteria": "T3, N0–N1, M0",
      "clinical_meaning": "Large tumor (>5 cm) with or without regional lymph node involvement, no distant metastasis",
      "five_yr_survival": "Regional disease: 60% five-year survival",
      "treatment_intent": "Curative; chemoRT"
    },
    {
      "group": "Stage IIIB",
      "criteria": "T4, N0, M0",
      "clinical_meaning": "Tumor invading adjacent organs (vagina, urethra, bladder) without regional lymph node involvement or distant metastasis",
      "five_yr_survival": "Regional disease: 60% five-year survival; worst prognosis among node-negative groups",
      "treatment_intent": "Curative; chemoRT"
    },
    {
      "group": "Stage IIIC",
      "criteria": "T4, N1, M0",
      "clinical_meaning": "Tumor invading adjacent organs with regional lymph node involvement, no distant metastasis",
      "five_yr_survival": "Regional disease: 60% five-year survival; worst prognosis category",
      "treatment_intent": "Curative; chemoRT"
    },
    {
      "group": "Stage IV",
      "criteria": "Any T, Any N, M1",
      "clinical_meaning": "Any primary tumor with distant metastasis",
      "five_yr_survival": "Distant metastasis: 30.5% five-year survival",
      "treatment_intent": "Palliative; systemic therapy; chemoRT to primary site may be considered for local control"
    }
  ],
  "staging_pearls": [
    "The AJCC 9th edition removed the former N2 and N3 categories by locations of positive nodes and introduced new categories N1a, N1b, and N1c based on specific nodal regions",
    "N1a represents metastasis in inguinal, mesorectal, superior rectal, internal iliac, or obturator nodes; N1b represents external iliac nodes; N1c represents external iliac with any N1a nodes",
    "Both anal canal and perianal tumors use the AJCC anus staging system (previously perianal cancer used the skin cancer staging system)",
    "Prognosis is related to tumor size and lymph node metastases; male sex, positive lymph nodes, and tumor size >5 cm are independently prognostic for worse OS",
    "The same staging system applies to both anal canal and perianal cancers to avoid undertreatment of perianal cancers that may involve the anal canal",
    "T stage is primarily determined through clinical examination (DRE, anoscopy) rather than pathologic staging since primary treatment does not involve surgical excision",
    "Para-aortic lymph nodes that can be included in a radiation field may be treated with definitive chemoRT, although only limited retrospective data support this use",
    "Distal anal cancers present with a higher incidence of inguinal node metastases, but inguinal node metastases can occur in proximal anal cancer as well since lym"
  ]
}
